import React from 'react';

export enum EnergySource {
    Solar = 'Solar',
    Wind = 'Eòlica',
    Hydro = 'Hidràulica',
    Nuclear = 'Nuclear',
    Fossil = 'Combustibles Fòssils',
    Biofuel = 'Biocombustible',
    EolicaMarina = 'Eòlica Marina',
    Termosolar = 'Termosolar'
}

export enum Quarter {
    Q1 = "1r Trimestre",
    Q2 = "2n Trimestre",
    Q3 = "3r Trimestre",
    Q4 = "4t Trimestre"
}

export enum DifficultyLevel {
    Easy = 'Easy',
    Medium = 'Medium',
    Hard = 'Hard',
}

export interface PowerPlant {
    id: number;
    name: string;
    type: EnergySource;
    capacity: number; // in MW
    upkeep: number; // M€ per trimestre
    operationalTurn: number;
    isActive: boolean;
    outputPercentage: number; // 0 to 1, representing current output
    isForcedOffline: boolean; // True if an event forces it offline
    isDecommissioned: boolean;
    constructionStartTurn: number;
}

export interface CostModifier {
    source: EnergySource;
    multiplier: number;
    duration: number | 'permanent';
}

export interface UpkeepModifier {
    id: string;
    multiplier: number;
    duration: number | 'permanent';
}

export interface ConstructionBan {
    source: EnergySource;
    duration: number | 'permanent';
}

export interface CapacityModifier {
    source: EnergySource;
    multiplier: number;
    duration: number | 'permanent';
}

export enum NewsCategory {
    Economic = "Economia",
    Political = "Política",
    Social = "Social",
    Environmental = "Medi Ambient",
    International = "Internacional",
    // FIX: Add Technology to NewsCategory enum to resolve compilation error in constants.ts.
    Technology = "Tecnologia"
}

export interface NewsArticle {
    id: string;
    headline: string;
    content: string;
    category: NewsCategory;
    turnGenerated: number;
}

export interface MajorDecisionRecord {
    turn: number;
    event: GameEvent;
    decisionText: string;
}

// Tracks one-off financial events within a turn for detailed breakdown
export interface TurnEventFinancial {
    id: string;
    description: string;
    amount: number; // positive for income, negative for expense
    relatedPlantId?: number;
    relatedPolicyId?: PolicyId;
}

export interface ApprovalRatings {
    citizen: number; // Ciutadania
    business: number; // Empresariat
    political: number; // Suport Polític
    environmentalist: number; // Ecologistes
}

export interface ApprovalModifier {
    id: string;
    description: string;
    changes: Partial<ApprovalRatings>;
    relatedPlantId?: number;
    relatedPolicyId?: PolicyId;
}

export type PolicyId = 'rehabilitation' | 'carbon_tax' | 'wind_rd' | 'grid_modernization' | 'self_consumption' | 'battery_storage' | 'green_hydrogen' | 'solar_efficiency' | 'energy_education' | 'nuclear_life_extension' | 'simplify_bureaucracy' | 'green_fiscal_reform' | 'predictive_maintenance' | 'hydro_rd' | 'offshore_wind_unlock' | 'solar_thermal_unlock' | 'corporate_tax_cut' | 'windfall_tax' | 'energy_check' | 'electrification_incentives' | 'appliance_renewal' | 'eco_tourist_tax' | 'aragon_energy_pact';
export type PolicyStatus = 'available' | 'enacting' | 'active' | 'rejected';
export type PolicyCategory = "Eficiència i Demanda" | "Fiscalitat i Mercat" | "R+D i Tecnologia" | "Infraestructura Estratègica";

export interface Policy {
    id: PolicyId;
    title: string;
    category: PolicyCategory;
    description: string;
    pros: string[];
    cons: string[];
    cost: number; // one-time cost
    implementationTime: number; // turns
    effect: (currentState: GameState) => Partial<GameState>;
    enactmentApprovalModifier?: Partial<ApprovalRatings>;
    baseSuccessChance: number;
    scoreImpact: number;
}

export interface ActivePolicy {
    policyId: PolicyId;
    status: PolicyStatus;
    turnEnacted: number;
    turnWillResolve: number;
}

export interface ClimateEvent {
    id: string;
    description: string;
    modifiers: {
        solar: number; // e.g., 0.1 for +10%, -0.15 for -15%
        wind: number;
        hydro: number;
    };
}

export interface GameState {
    playerName: string;
    budget: number; // in millions of €
    approvalRatings: ApprovalRatings;
    overallApproval: number;
    co2Emissions: number; // in tons per turn
    totalProduction: number; // in MW
    totalDemand: number; // in MW
    powerPlants: PowerPlant[];
    baseDemand: number;
    hydroModifier: number; // 1.0 is normal, < 1.0 is drought
    energyDeficit: number; // in MW, amount to import
    hasReceivedEUWarning: boolean;
    hasTriggeredClimateProtest: boolean;
    hasTriggeredCO2ReductionEvent: boolean;
    costModifiers: CostModifier[];
    constructionBans: ConstructionBan[];
    capacityModifiers: CapacityModifier[];
    newsFeed: NewsArticle[];
    lastAction: { type: 'build', plantType: EnergySource } | null;
    constructionDemandModifiers: { id: string; relatedPlantId: number; demand: number, duration: number }[];
    triggeredEventTitles: string[];
    history: GameState[]; // For end-game summary
    gameStatus: GameStatus;
    majorDecisions: MajorDecisionRecord[];
    scheduledEvent: GameEvent | null;
    // New properties for new events
    hasInvestedInBatteries: boolean;
    hasInvestedInHydrogen: boolean;
    nuclearMaintenanceRisk: boolean;
    surplusSalePriceMultiplier: number;
    importEnergyPriceMultiplier: number;
    recurrentUpkeep: number;
    // Dynamic Market
    marketPricePerMW: number;
    // Difficulty
    difficulty: DifficultyLevel;
    penaltyMultiplier: number;
    // Financial Breakdown
    currentTurnFinancialEvents: TurnEventFinancial[];
    // Approval Breakdown
    currentTurnApprovalModifiers: ApprovalModifier[];
    // Policies
    policies: ActivePolicy[];
    plantBuiltThisTurn: boolean;
    displayedPolicyIds: PolicyId[];
    // Dynamic economy
    taxRevenuePerTurn: number;
    upkeepModifiers: UpkeepModifier[];
    temporaryDemandModifier: { multiplier: number, duration: number } | null;
    // Reactive crisis events
    hasTriggeredBusinessCrisis: boolean;
    hasTriggeredEnvironmentalistCrisis: boolean;
    hasTriggeredPoliticalCrisis: boolean;
    hasTriggeredCitizenCrisis: boolean;
    currentClimateEvent: ClimateEvent | null;
    // Dynamic start date
    startYear: number;
    startQuarterIndex: number;
}

export interface Decision {
    text: string;
    explanation: (currentState: GameState, difficulty: DifficultyLevel) => string;
    effect: (currentState: GameState, penaltyMultiplier: number) => Partial<GameState>;
    strategicAdvice: string;
}

export type EventCategory = 'Tecnologia i Indústria' | 'Clima i Desastres' | 'Política i Societat' | 'Economia i Mercat' | 'Reacció a Construcció' | 'Crisi Governamental';

export interface GameEvent {
    title: string;
    description: (difficulty: DifficultyLevel) => string;
    decisions: Decision[];
    allowedQuarters?: Quarter[];
    minTurn?: number; // Event cannot appear before this turn
    allowedDifficulties?: DifficultyLevel[];
    category?: EventCategory;
}

export interface PowerPlantConfig {
    name: string;
    cost: number;
    capacity: number;
    buildTime: number; // in turns
    co2: number; // tons per MW per turn
    upkeep: number;
    constructionEnergyDemand: number; // total MW required over the construction period
    approvalModifier: Partial<ApprovalRatings>;
}

export enum GameStatus {
    Playing = 'Playing',
    Won = 'Won',
    Lost = 'Lost'
}

export interface TurnNotification {
    id: string;
    message: string;
    type: 'success' | 'failure' | 'info';
}

export interface AnalysisReport {
    title: string;
    sections: {
        title: string;
        points: string[];
        icon: React.ReactNode;
    }[];
    conclusion: string;
}

import React, { useState, useMemo } from 'react';
import { GameEvent, Decision, GameState, EnergySource, Quarter, DifficultyLevel } from '../types';
import { CAPACITY_FACTORS, QUARTERS } from '../constants';
import { CheckCircleIcon, XCircleIcon, InfoIcon, CoinIcon, HeartIcon, CloudIcon, ZapIcon, BoltIcon, ShieldCheckIcon, ChevronDownIcon, CalendarIcon } from './Icons';
import { PLANT_ICONS } from './Icons';


interface EventScreenProps {
    event: GameEvent;
    onDecision: (decision: Decision) => void;
    gameState: GameState;
    turn: number;
    seasonalProductionMultipliers: Record<EnergySource, number>;
}

const EventScreen: React.FC<EventScreenProps> = ({ event, onDecision, gameState, turn, seasonalProductionMultipliers }) => {

    const [isEnergyOverviewOpen, setIsEnergyOverviewOpen] = useState(false);
    const { difficulty, startYear, startQuarterIndex } = gameState;
    const effectiveTurn = turn + startQuarterIndex;
    const currentQuarter = QUARTERS[effectiveTurn % 4];
    const currentYear = startYear + Math.floor(effectiveTurn / 4);

    const productionBySource = useMemo(() => {
        const operationalPlants = gameState.powerPlants.filter(p => p.operationalTurn <= turn && p.isActive && !p.isForcedOffline && !p.isDecommissioned);
        const production: Partial<Record<EnergySource, number>> = {};

        Object.values(EnergySource).forEach(source => {
            const sourcePlants = operationalPlants.filter(p => p.type === source);
            const sourceProduction = sourcePlants.reduce((acc, plant) => {
                let baseProduction = plant.capacity * CAPACITY_FACTORS[plant.type] * plant.outputPercentage;
                baseProduction *= seasonalProductionMultipliers[plant.type];
                return acc + baseProduction;
            }, 0);
            if(sourceProduction > 0) {
                 production[source] = sourceProduction;
            }
        });
        return production;
    }, [gameState.powerPlants, turn, seasonalProductionMultipliers]);

    const energySovereignty = gameState.totalDemand > 0 ? (gameState.totalProduction / gameState.totalDemand) * 100 : 100;

    const parseExplanation = (text: string) => {
        const prosMatch = text.match(/\*\*Pros:\*\*\s*([\s\S]*?)(?=\n\*\*Contres:\*\*|\n\*\*Conclusió:\*\*|$)/);
        const consMatch = text.match(/\*\*Contres:\*\*\s*([\s\S]*?)(?=\n\*\*Conclusió:\*\*|$)/);
        const conclusionMatch = text.match(/\*\*Conclusió:\*\*\s*([\s\S]*)/);

        const pros = prosMatch ? prosMatch[1].trim().split('\n').filter(line => line.trim() !== '') : [];
        const cons = consMatch ? consMatch[1].trim().split('\n').filter(line => line.trim() !== '') : [];
        const conclusion = conclusionMatch ? conclusionMatch[1].trim() : '';

        return { pros, cons, conclusion };
    };

    const narration = event.description(difficulty);

    return (
        <div className="min-h-screen overflow-y-auto p-4 sm:p-6 lg:p-8 flex items-center justify-center">
            <div className="bg-white rounded-lg shadow-xl w-full max-w-5xl border border-teal-300 my-8 mx-auto flex flex-col">
                <div className="p-6">
                    <h2 className="text-2xl font-bold text-teal-600 mb-2 text-center">{event.title}</h2>
                     <div className="flex justify-center items-center gap-2 text-md text-slate-500 mb-4 font-semibold">
                        <CalendarIcon className="w-5 h-5" />
                        <span>{currentQuarter} de {currentYear}</span>
                    </div>
                    <div className="text-slate-600 my-4 bg-slate-100 rounded-lg p-4 border border-slate-200">
                        <p className="italic text-center">"{narration}"</p>
                    </div>
                </div>

                 <div className="px-6 pb-4 border-t border-b border-slate-200 bg-slate-50/50">
                    <h3 className="text-lg font-semibold text-slate-700 my-3 text-center">Estat Actual</h3>
                    <div className="grid grid-cols-3 gap-4 text-center">
                        <div className="bg-white p-3 rounded-lg border border-slate-200">
                            <CoinIcon className="w-7 h-7 mx-auto text-yellow-500 mb-1" />
                            <span className="font-bold text-lg">{gameState.budget.toLocaleString()} M€</span>
                            <span className="text-xs block text-slate-500">Pressupost</span>
                        </div>
                         <div className="bg-white p-3 rounded-lg border border-slate-200">
                            <HeartIcon className="w-7 h-7 mx-auto text-rose-500 mb-1" />
                            <span className="font-bold text-lg">{gameState.overallApproval.toFixed(0)}%</span>
                            <span className="text-xs block text-slate-500">Aprov. General</span>
                        </div>
                         <div className="bg-white p-3 rounded-lg border border-slate-200">
                            <CloudIcon className="w-7 h-7 mx-auto text-sky-500 mb-1" />
                            <span className="font-bold text-lg">{gameState.co2Emissions.toLocaleString()} t</span>
                            <span className="text-xs block text-slate-500">Emissions CO₂</span>
                        </div>
                    </div>
                    {/* New Energy Overview Panel */}
                     <div className="mt-4">
                        <button onClick={() => setIsEnergyOverviewOpen(!isEnergyOverviewOpen)} className="w-full flex justify-between items-center text-left bg-slate-100 hover:bg-slate-200 p-2 rounded-lg text-sm font-semibold text-slate-700 transition-colors border border-slate-200">
                            <span>Panorama Energètic Actual</span>
                            <ChevronDownIcon className={`w-5 h-5 transition-transform ${isEnergyOverviewOpen ? 'rotate-180' : ''}`} />
                        </button>
                        {isEnergyOverviewOpen && (
                            <div className="mt-2 bg-white p-3 rounded-lg border border-slate-200">
                                <div className="grid grid-cols-2 sm:grid-cols-3 gap-3">
                                    {Object.entries(productionBySource).map(([source, production]) => (
                                        <div key={source} className="flex items-center space-x-2 text-sm">
                                            {PLANT_ICONS[source as EnergySource]}
                                            <span className="font-semibold text-slate-600">{source}:</span>
                                            <span className="text-slate-800 font-medium">{(production as number).toFixed(0)} MW</span>
                                        </div>
                                    ))}
                                </div>
                                <div className="mt-3 pt-3 border-t border-slate-200 grid grid-cols-3 text-center text-sm">
                                    <div className="font-semibold"><ZapIcon className="w-4 h-4 inline-block mr-1" />{gameState.totalProduction.toFixed(0)} <span className="text-slate-500">MW Prod.</span></div>
                                    <div className="font-semibold"><BoltIcon className="w-4 h-4 inline-block mr-1" />{gameState.totalDemand.toFixed(0)} <span className="text-slate-500">MW Dem.</span></div>
                                    <div className="font-semibold"><ShieldCheckIcon className="w-4 h-4 inline-block mr-1" />{energySovereignty.toFixed(0)}<span className="text-slate-500">% Sobir.</span></div>
                                </div>
                            </div>
                        )}
                    </div>
                </div>

                <div className="overflow-y-auto px-6 py-6 space-y-6">
                    {event.decisions.map((decision, index) => {
                        const { pros, cons, conclusion } = parseExplanation(decision.explanation(gameState, difficulty));

                        return (
                            <div key={index} className="bg-slate-50 p-5 rounded-lg border border-slate-200 flex flex-col">
                                <button
                                    onClick={() => onDecision(decision)}
                                    className="w-full bg-white hover:bg-teal-600 text-slate-800 hover:text-white font-semibold py-3 px-4 rounded-lg transition duration-300 ease-in-out transform hover:scale-105 focus:outline-none focus:ring-2 focus:ring-teal-500 focus:ring-opacity-50 border border-teal-500/50 mb-4 shadow-sm"
                                >
                                    {decision.text}
                                </button>
                                <div className="flex-grow">
                                    <div className="grid grid-cols-1 md:grid-cols-2 gap-x-6 gap-y-4">
                                        {/* Pros Column */}
                                        <div>
                                            <h4 className="flex items-center text-lg font-semibold text-green-600 mb-2">
                                                <CheckCircleIcon className="w-6 h-6 mr-2 flex-shrink-0" />
                                                Pros
                                            </h4>
                                            <ul className="space-y-1.5 pl-2">
                                                {pros.map((pro, i) => (
                                                    <li key={`pro-${i}`} className="text-sm text-slate-700 flex items-start">
                                                        <span className="text-green-500 mr-2 mt-1">&#10003;</span>
                                                        <span>{pro}</span>
                                                    </li>
                                                ))}
                                            </ul>
                                        </div>

                                        {/* Cons Column */}
                                        <div>
                                            <h4 className="flex items-center text-lg font-semibold text-red-600 mb-2">
                                                <XCircleIcon className="w-6 h-6 mr-2 flex-shrink-0" />
                                                Contres
                                            </h4>
                                            <ul className="space-y-1.5 pl-2">
                                                {cons.map((con, i) => (
                                                    <li key={`con-${i}`} className="text-sm text-slate-700 flex items-start">
                                                        <span className="text-red-500 mr-2 mt-1">&#10007;</span>
                                                        <span>{con}</span>
                                                    </li>
                                                ))}
                                            </ul>
                                        </div>
                                    </div>

                                    {/* Conclusion */}
                                    {conclusion && (
                                        <div className="mt-4 pt-4 border-t border-slate-200">
                                            <h4 className="flex items-center text-md font-semibold text-teal-600 mb-2">
                                                <InfoIcon className="w-5 h-5 mr-2 flex-shrink-0" />
                                                Conclusió Estratègica
                                            </h4>
                                            <p className="text-sm text-slate-500 italic">{conclusion}</p>
                                        </div>
                                    )}
                                </div>
                            </div>
                        );
                    })}
                </div>
            </div>
        </div>
    );
};

export default EventScreen;

import React from 'react';
import { PowerPlantConfig, EnergySource, GameState } from '../types';
import { PLANT_CONSTRUCTION_PROS_CONS, AGENT_CONFIG } from '../constants';
import { PLANT_ICONS } from './Icons';

interface ConstructionChoiceScreenProps {
    plantType: EnergySource;
    options: PowerPlantConfig[];
    onSelect: (config: PowerPlantConfig) => void;
    onCancel: () => void;
    gameState: GameState;
}

const ConstructionChoiceScreen: React.FC<ConstructionChoiceScreenProps> = ({ plantType, options, onSelect, onCancel, gameState }) => {
    const prosCons = PLANT_CONSTRUCTION_PROS_CONS[plantType];

    const getModifiedCost = (config: PowerPlantConfig): number => {
        const costModifier = gameState.costModifiers.find(m => m.source === plantType);
        return costModifier ? config.cost * costModifier.multiplier : config.cost;
    };

    return (
        <div className="fixed inset-0 bg-slate-900 bg-opacity-75 flex items-start sm:items-center justify-center overflow-y-auto p-4 z-50">
            <div className="bg-white rounded-lg shadow-xl w-full max-w-5xl border border-teal-300 flex flex-col">
                <div className="p-6 text-center">
                    <div className="flex items-center justify-center text-3xl font-bold text-slate-800 tracking-wider">
                        {PLANT_ICONS[plantType]}
                        <h1 className="ml-4">Triar Escala del Projecte {plantType}</h1>
                    </div>
                    <p className="text-teal-600 mt-2 text-lg">En mode Difícil, cada construcció és una decisió estratègica.</p>
                </div>

                <div className="px-6 pb-6 grid grid-cols-1 md:grid-cols-3 gap-6">
                    {options.map((option, index) => {
                        const finalCost = getModifiedCost(option);
                        const canAfford = gameState.budget >= finalCost;
                        const approvalModifiers = Object.entries(option.approvalModifier).filter(([, val]) => val !== 0 && val !== undefined);


                        return (
                            <div key={index} className={`bg-slate-50 p-4 rounded-lg flex flex-col h-full border-2 transition-all ${canAfford ? 'border-slate-200 hover:border-teal-500' : 'border-red-300/50 opacity-70'}`}>
                                <h3 className="text-xl font-bold text-center text-yellow-600 mb-3">{option.name}</h3>
                                <div className="space-y-2 text-sm flex-grow text-slate-600">
                                    <div className="flex justify-between"><span>Capacitat:</span> <span className="font-mono font-bold text-slate-800">{option.capacity.toLocaleString()} MW</span></div>
                                    <div className="flex justify-between"><span>Cost:</span> <span className={`font-mono font-bold ${canAfford ? 'text-slate-800' : 'text-red-500'}`}>{finalCost.toLocaleString()} M€</span></div>
                                    <div className="flex justify-between"><span>Temps Construcció:</span> <span className="font-mono font-bold text-slate-800">{option.buildTime} trimestres</span></div>
                                    <div className="flex justify-between"><span>Manteniment:</span> <span className="font-mono font-bold text-slate-800">{option.upkeep.toLocaleString()} M€/trim.</span></div>
                                </div>
                                <div className="mt-4 pt-3 border-t border-slate-200">
                                    <h4 className="text-center text-sm font-semibold text-slate-500 mb-2">Impacte en l'Aprovació</h4>
                                    {approvalModifiers.length > 0 ? (
                                        <div className="grid grid-cols-2 gap-2 text-xs">
                                            {approvalModifiers.map(([agent, value]) => {
                                                const agentConfig = AGENT_CONFIG[agent as keyof typeof AGENT_CONFIG];
                                                return (
                                                    <div key={agent} className="flex items-center justify-between bg-white p-1.5 rounded border border-slate-200">
                                                        <div className="flex items-center gap-1.5 text-slate-600">
                                                           <div className={`w-4 h-4 ${agentConfig.color}`}>{agentConfig.icon}</div>
                                                           <span>{agentConfig.label}</span>
                                                        </div>
                                                        <span className={`font-mono font-bold ${(value as number) >= 0 ? 'text-green-600' : 'text-red-600'}`}>
                                                            {(value as number) > 0 ? '+' : ''}{value}%
                                                        </span>
                                                    </div>
                                                );
                                            })}
                                        </div>
                                    ) : (
                                        <p className="text-center text-xs text-slate-400 italic">Cap canvi significatiu</p>
                                    )}
                                </div>
                                <button
                                    onClick={() => onSelect(option)}
                                    disabled={!canAfford}
                                    className={`w-full font-semibold py-2 px-4 rounded-lg transition mt-4 ${
                                        canAfford 
                                        ? 'bg-teal-600 hover:bg-teal-700 text-white' 
                                        : 'bg-slate-300 cursor-not-allowed text-slate-500'
                                    }`}
                                >
                                    {canAfford ? 'Seleccionar Projecte' : 'Fons Insuficients'}
                                </button>
                            </div>
                        );
                    })}
                </div>

                <div className="px-6 pb-6 bg-slate-100">
                    <div className="grid grid-cols-1 md:grid-cols-2 gap-4 text-sm p-4 text-slate-600">
                        <div>
                            <h4 className="font-bold text-green-600 mb-1">Pros de {plantType}</h4>
                            <ul className="list-disc pl-5 space-y-1">
                                {prosCons.pros.map((pro, i) => <li key={i}>{pro}</li>)}
                            </ul>
                        </div>
                        <div>
                            <h4 className="font-bold text-red-600 mb-1">Contres de {plantType}</h4>
                            <ul className="list-disc pl-5 space-y-1">
                                {prosCons.cons.map((con, i) => <li key={i}>{con}</li>)}
                            </ul>
                        </div>
                    </div>
                </div>

                <div className="p-4 mt-auto bg-slate-50/50 rounded-b-lg text-center">
                    <button
                        onClick={onCancel}
                        className="bg-slate-200 hover:bg-slate-300 text-slate-800 font-semibold py-2 px-6 rounded-lg transition duration-300"
                    >
                        Tornar a la Gestió Energètica
                    </button>
                </div>
            </div>
        </div>
    );
};

export default ConstructionChoiceScreen;
